Javascript.validate:
			var value = Services.getValue(AnnualInterestPercentage.dataBinding); 
			var errCode = null;

			if((!CaseManValidationHelper.validateNumber(value)  && !CaseManValidationHelper.validateFloatNumber(value)) || (value < 1) || (value > 100))
			{
				errCode = ErrorCode.getErrorCode("CaseMan_Reports_PercentageNotInCorrectRange_Msg");
			}
			return errCode;

Javascript.transformToModel:
if(value != "" && value != null)
{
	if(CaseManValidationHelper.validateNumber(value)){}
	else if(CaseManValidationHelper.validateFloatNumber(value))
	{
		value = parseFloat(value).toFixed(2);
	}
}
return value;

Javascript.transformToDisplay:
if(value != "" && value != null)
{
	if(CaseManValidationHelper.validateNumber(value)){}	
	else if(CaseManValidationHelper.validateFloatNumber(value))
	{
		value = parseFloat(value).toFixed(2);	
	}
}
return value;
